using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var bingApiKey = Environment.GetEnvironmentVariable("BING_API_KEY"); // optional

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍  Researching: {topic}\n");

// --- Build the AI client with tools ---
IChatClient innerClient = new OpenAIClient(openAiKey)
    .GetChatClient("gpt-4o")
    .AsIChatClient();

var notepad = new Notepad();
var webSearch = new WebSearchTool(bingApiKey);

IChatClient agent = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(webSearch.SearchWeb),
        AIFunctionFactory.Create(webSearch.FetchPage),
        AIFunctionFactory.Create(notepad.AddNote),
        AIFunctionFactory.Create(notepad.GetNotes),
    ]
};

// --- Agent system prompt ---
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to thoroughly research a topic the user gives you.

        Workflow:
        1. Search the web for relevant information (multiple queries if needed).
        2. Fetch promising pages to get detailed content.
        3. Take notes on key findings using the note-taking tool.
        4. Once you have gathered enough information, retrieve all your notes and
           produce a well-structured summary with references.

        Be thorough: use at least 2-3 different search queries to cover the topic broadly.
        Always take notes before writing the final summary.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary:\n\n{topic}")
};

// --- Agent loop ---
Console.WriteLine("Agent is working...\n");

var response = await agent.GetResponseAsync(messages, chatOptions);

Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n═══════════════════════════════════════════");

if (notepad.NoteCount > 0)
{
    Console.WriteLine($"\n📝 {notepad.NoteCount} note(s) were taken during research.");
}

// --- Helper ---
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input) ? "Recent advances in quantum computing 2026" : input;
}

