{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } }
    };

    [Description("Search the web for a query and return a list of result titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        if (!string.IsNullOrEmpty(bingApiKey))
            return await SearchWithBing(query);

        return await SearchFallback(query);
    }

    [Description("Fetch the text content of a web page given its URL. Returns the first ~3000 characters.")]
    public async Task<string> FetchPage(
        [Description("Full URL of the page to fetch")] string url)
    {
        Console.WriteLine($"  📄 Fetching: {url}");
        try
        {
            var html = await Http.GetStringAsync(url);
            // Crude HTML-to-text
            var text = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", " ");
            text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ").Trim();
            return text.Length > 3000 ? text[..3000] : text;
        }
        catch (Exception ex)
        {
            return $"Error fetching page: {ex.Message}";
        }
    }

    private async Task<string> SearchWithBing(string query)
    {
        using var request = new HttpRequestMessage(HttpMethod.Get,
            $"https://api.bing.microsoft.com/v7.0/search?q={Uri.EscapeDataString(query)}&count=5");
        request.Headers.Add("Ocp-Apim-Subscription-Key", bingApiKey);

        var response = await Http.SendAsync(request);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
        var results = new List<string>();

        if (doc.RootElement.TryGetProperty("webPages", out var pages) &&
            pages.TryGetProperty("value", out var values))
        {
            foreach (var item in values.EnumerateArray())
            {
                var title = item.GetProperty("name").GetString();
                var snippet = item.GetProperty("snippet").GetString();
                var url = item.GetProperty("url").GetString();
                results.Add($"- **{title}**\n  {snippet}\n  URL: {url}");
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found.";
    }

    private static async Task<string> SearchFallback(string query)
    {
        // Use DuckDuckGo HTML lite as a no-key fallback
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url);

            var results = new List<string>();
            var linkPattern = new System.Text.RegularExpressions.Regex(
                @"<a[^>]+class=""result__a""[^>]*href=""([^""]+)""[^>]*>(.*?)</a>.*?<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
                System.Text.RegularExpressions.RegexOptions.Singleline);

            foreach (System.Text.RegularExpressions.Match m in linkPattern.Matches(html))
            {
                if (results.Count >= 5) break;
                var title = StripHtml(m.Groups[2].Value);
                var snippet = StripHtml(m.Groups[3].Value);
                var link = m.Groups[1].Value;
                results.Add($"- **{title}**\n  {snippet}\n  URL: {link}");
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : "No results found. Try a different query.";
        }
        catch (Exception ex)
        {
            return $"Search error: {ex.Message}";
        }
    }

    private static string StripHtml(string html) =>
        System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", "").Trim();
}

/// <summary>Note-taking tool — lets the agent collect and review findings.</summary>
sealed class Notepad
{
    private readonly List<(DateTime Timestamp, string Note)> _notes = [];

    public int NoteCount => _notes.Count;

    [Description("Save a research note. Use this to record key findings, facts, or quotes from sources.")]
    public string AddNote(
        [Description("The note content to save")] string content,
        [Description("Optional source URL or reference")] string? source = null)
    {
        var entry = source is not null ? $"{content} (source: {source})" : content;
        _notes.Add((DateTime.UtcNow, entry));
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        return string.Join("\n", _notes.Select((n, i) =>
            $"[{i + 1}] {n.Note}"));
    }
}

